function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency Matrix
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let count = 0;

    // Helper to count set bits (popcount)
    function popcount(mask) {
        let count = 0;
        let m = mask;
        while (m > 0) {
            m &= (m - 1);
            count++;
        }
        return count;
    }

    // Iterate through all non-empty subsets (masks 1 to 2^N - 1)
    const totalMasks = 1 << N;
    for (let M = 1; M < totalMasks; M++) {

        // --- Condition 2: Check Sum Parity ---
        let sum = 0;
        for (let i = 0; i < N; i++) {
            if ((M & (1 << i)) !== 0) {
                sum += nums[i];
            }
        }

        // If sum is odd, skip
        if (sum % 2 !== 0) {
            continue;
        }

        // --- Condition 1: Check Connectivity using BFS ---

        // Find a starting node 'r' (guaranteed to exist since M >= 1)
        let startNode = -1;
        for (let i = 0; i < N; i++) {
            if ((M & (1 << i)) !== 0) {
                startNode = i;
                break;
            }
        }

        // BFS initialization
        const queue = [startNode];
        const visited = new Array(N).fill(false);
        visited[startNode] = true;
        let visitedCount = 1;
        let head = 0;

        while (head < queue.length) {
            const u = queue[head++];

            for (let v = 0; v < N; v++) {
                // Check if v is in subset M, an edge exists (u, v), and v hasn't been visited
                if ((M & (1 << v)) !== 0 && adj[u][v] && !visited[v]) {
                    visited[v] = true;
                    queue.push(v);
                    visitedCount++;
                }
            }
        }

        const totalNodesInS = popcount(M);

        if (visitedCount === totalNodesInS) {
            // Both conditions met: Connected AND Sum is Even
            count++;
        }
    }

    return count;
}

